import random
import math
import heapq

GPU_MEM_SIZE = 80  # GB

def compute_model_placement(gpu_num: int, models: list) -> dict:
    """
    Optimized model placement using a multi-strategy approach:
    1. Sort models by density (req_rate/slo per GB)
    2. Use bin-packing with KVPR-aware scoring for initial placement
    3. Apply simulated annealing with strategic moves
    4. Perform final refinement through greedy swaps
    """

    def kvpr_gpu(gpu_models):
        """Calculate KVPR for a single GPU."""
        if not gpu_models:
            return 0.0

        total_size = sum(m.model_size for m in gpu_models)
        if total_size >= GPU_MEM_SIZE:
            return float('inf')

        remaining = GPU_MEM_SIZE - total_size
        total_weight = sum(m.req_rate / m.slo for m in gpu_models)
        return total_weight / remaining if remaining > 1e-6 else float('inf')

    def max_kvpr(placement):
        """Get maximum KVPR across all GPUs."""
        max_val = 0.0
        for gpu_id in range(gpu_num):
            kvpr = kvpr_gpu(placement[gpu_id])
            if kvpr > max_val:
                max_val = kvpr
        return max_val

    # Precompute model characteristics
    for model in models:
        model.density = (model.req_rate / model.slo) / (model.model_size + 1e-6)
        model.weight = model.req_rate / model.slo

    # Sort by density descending (most "expensive" per GB first)
    sorted_models = sorted(models, key=lambda m: m.density, reverse=True)

    # Initial placement using best-fit with KVPR consideration
    placement = {i: [] for i in range(gpu_num)}
    gpu_sizes = [0] * gpu_num
    gpu_weights = [0.0] * gpu_num

    for model in sorted_models:
        best_gpu = -1
        best_score = float('inf')

        for gpu_id in range(gpu_num):
            if gpu_sizes[gpu_id] + model.model_size <= GPU_MEM_SIZE:
                # Calculate potential KVPR after placement
                new_size = gpu_sizes[gpu_id] + model.model_size
                new_weight = gpu_weights[gpu_id] + model.weight
                remaining = GPU_MEM_SIZE - new_size

                if remaining <= 0:
                    continue

                potential_kvpr = new_weight / remaining

                # Score balances KVPR and remaining space
                score = potential_kvpr * (1.0 + 0.1 * (new_size / GPU_MEM_SIZE))

                if score < best_score:
                    best_score = score
                    best_gpu = gpu_id

        if best_gpu != -1:
            placement[best_gpu].append(model)
            gpu_sizes[best_gpu] += model.model_size
            gpu_weights[best_gpu] += model.weight
        else:
            # Fallback: place on GPU with most remaining space
            for gpu_id in range(gpu_num):
                if gpu_sizes[gpu_id] + model.model_size <= GPU_MEM_SIZE:
                    placement[gpu_id].append(model)
                    gpu_sizes[gpu_id] += model.model_size
                    gpu_weights[gpu_id] += model.weight
                    break

    # Simulated annealing optimization
    current_energy = max_kvpr(placement)
    best_placement = {i: list(placement[i]) for i in range(gpu_num)}
    best_energy = current_energy

    # Temperature schedule
    T_init = max(1.0, current_energy * 0.1)
    T_min = 1e-6
    alpha = 0.9995
    max_steps = 20000

    T = T_init
    steps = 0

    while T > T_min and steps < max_steps:
        steps += 1

        # Generate neighbor: 60% relocate, 40% swap
        neighbor = {i: list(placement[i]) for i in range(gpu_num)}
        move_success = False

        if random.random() < 0.6:
            # Relocate move
            src_gpus = [i for i in range(gpu_num) if neighbor[i]]
            if src_gpus:
                src_gpu = random.choice(src_gpus)
                if neighbor[src_gpu]:
                    model_idx = random.randrange(len(neighbor[src_gpu]))
                    model = neighbor[src_gpu][model_idx]

                    dst_gpus = [i for i in range(gpu_num) if i != src_gpu]
                    random.shuffle(dst_gpus)

                    for dst_gpu in dst_gpus:
                        dst_size = sum(m.model_size for m in neighbor[dst_gpu])
                        if dst_size + model.model_size <= GPU_MEM_SIZE:
                            neighbor[src_gpu].pop(model_idx)
                            neighbor[dst_gpu].append(model)
                            move_success = True
                            break
        else:
            # Swap move
            gpu_pairs = [(i, j) for i in range(gpu_num) for j in range(i+1, gpu_num)]
            random.shuffle(gpu_pairs)

            for gpu1, gpu2 in gpu_pairs:
                if neighbor[gpu1] and neighbor[gpu2]:
                    idx1 = random.randrange(len(neighbor[gpu1]))
                    idx2 = random.randrange(len(neighbor[gpu2]))

                    model1 = neighbor[gpu1][idx1]
                    model2 = neighbor[gpu2][idx2]

                    size1 = sum(m.model_size for m in neighbor[gpu1]) - model1.model_size + model2.model_size
                    size2 = sum(m.model_size for m in neighbor[gpu2]) - model2.model_size + model1.model_size

                    if size1 <= GPU_MEM_SIZE and size2 <= GPU_MEM_SIZE:
                        neighbor[gpu1][idx1] = model2
                        neighbor[gpu2][idx2] = model1
                        move_success = True
                        break

        if not move_success:
            T *= alpha
            continue

        # Evaluate neighbor
        new_energy = max_kvpr(neighbor)
        delta = new_energy - current_energy

        # Metropolis criterion
        if delta < 0 or random.random() < math.exp(-delta / T):
            placement = neighbor
            current_energy = new_energy

            if new_energy < best_energy:
                best_placement = {i: list(neighbor[i]) for i in range(gpu_num)}
                best_energy = new_energy

        T *= alpha

    # Final refinement: greedy swaps
    improved = True
    while improved:
        improved = False
        current_kvprs = [kvpr_gpu(best_placement[i]) for i in range(gpu_num)]

        # Try to move models from high KVPR GPUs to low KVPR GPUs
        high_gpus = sorted(range(gpu_num), key=lambda i: current_kvprs[i], reverse=True)
        low_gpus = sorted(range(gpu_num), key=lambda i: current_kvprs[i])

        for src_gpu in high_gpus:
            for dst_gpu in low_gpus:
                if src_gpu == dst_gpu:
                    continue

                # Try moving each model from src to dst
                for model_idx, model in enumerate(best_placement[src_gpu]):
                    dst_size = sum(m.model_size for m in best_placement[dst_gpu])
                    if dst_size + model.model_size <= GPU_MEM_SIZE:
                        # Create trial placement
                        trial = {i: list(best_placement[i]) for i in range(gpu_num)}
                        trial[src_gpu].pop(model_idx)
                        trial[dst_gpu].append(model)

                        new_max = max_kvpr(trial)
                        if new_max < best_energy:
                            best_placement = trial
                            best_energy = new_max
                            improved = True
                            break
                if improved:
                    break
            if improved:
                break

        # Try pairwise swaps
        if not improved:
            for gpu1 in range(gpu_num):
                for gpu2 in range(gpu1 + 1, gpu_num):
                    for idx1, model1 in enumerate(best_placement[gpu1]):
                        for idx2, model2 in enumerate(best_placement[gpu2]):
                            size1 = sum(m.model_size for m in best_placement[gpu1]) - model1.model_size + model2.model_size
                            size2 = sum(m.model_size for m in best_placement[gpu2]) - model2.model_size + model1.model_size

                            if size1 <= GPU_MEM_SIZE and size2 <= GPU_MEM_SIZE:
                                trial = {i: list(best_placement[i]) for i in range(gpu_num)}
                                trial[gpu1][idx1] = model2
                                trial[gpu2][idx2] = model1

                                new_max = max_kvpr(trial)
                                if new_max < best_energy:
                                    best_placement = trial
                                    best_energy = new_max
                                    improved = True
                                    break
                        if improved:
                            break
                    if improved:
                        break
                if improved:
                    break

    return best_placement

