def compute_model_placement(gpu_num: int, models: list) -> dict:
    """
    Computes an optimal model placement using a greedy initial assignment
    followed by local search optimization to minimize maximum KVPR.
    """
    if not models:
        return {i: [] for i in range(gpu_num)}

    def calculate_gpu_kvpr(gpu_models):
        if not gpu_models:
            return 0.0
        total_size = sum(m.model_size for m in gpu_models)
        if total_size >= GPU_MEM_SIZE:
            return float('inf')
        remaining_mem = GPU_MEM_SIZE - total_size
        if remaining_mem <= 1e-9:
            return float('inf')
        total_weighted_rate = sum(m.req_rate / m.slo for m in gpu_models)
        if total_weighted_rate < 1e-9:
            return 0.0
        return total_weighted_rate / remaining_mem

    def get_max_kvpr(placement):
        max_kvpr = 0.0
        for gpu_id in placement:
            kvpr = calculate_gpu_kvpr(placement[gpu_id])
            max_kvpr = max(max_kvpr, kvpr)
        return max_kvpr

    # Initial greedy placement using First Fit Decreasing
    sorted_models = sorted(models, key=lambda m: (m.req_rate / m.slo, m.model_size), reverse=True)

    placement = {i: [] for i in range(gpu_num)}
    gpu_sizes = {i: 0 for i in range(gpu_num)}

    for model in sorted_models:
        best_gpu = -1
        min_potential_kvpr = float('inf')

        for gpu_id in range(gpu_num):
            if gpu_sizes[gpu_id] + model.model_size <= GPU_MEM_SIZE:
                # Calculate potential KVPR if model is added to this GPU
                temp_models = placement[gpu_id] + [model]
                potential_kvpr = calculate_gpu_kvpr(temp_models)

                if potential_kvpr < min_potential_kvpr:
                    min_potential_kvpr = potential_kvpr
                    best_gpu = gpu_id

        if best_gpu != -1:
            placement[best_gpu].append(model)
            gpu_sizes[best_gpu] += model.model_size
        else:
            # Fallback to any GPU that fits
            for gpu_id in range(gpu_num):
                if gpu_sizes[gpu_id] + model.model_size <= GPU_MEM_SIZE:
                    placement[gpu_id].append(model)
                    gpu_sizes[gpu_id] += model.model_size
                    break

    # Local search refinement
    max_iterations = 200
    for _ in range(max_iterations):
        current_max_kvpr = get_max_kvpr(placement)
        best_improvement = 1e-9
        best_move = None

        # Try relocation moves
        for src_gpu in range(gpu_num):
            for i, model in enumerate(placement[src_gpu]):
                for dst_gpu in range(gpu_num):
                    if src_gpu == dst_gpu:
                        continue
                    if gpu_sizes[dst_gpu] + model.model_size <= GPU_MEM_SIZE:
                        # Simulate move
                        temp_placement = {}
                        for gid, models_list in placement.items():
                            temp_placement[gid] = list(models_list)

                        temp_placement[src_gpu].pop(i)
                        temp_placement[dst_gpu].append(model)

                        new_max_kvpr = get_max_kvpr(temp_placement)
                        improvement = current_max_kvpr - new_max_kvpr

                        if improvement > best_improvement:
                            best_improvement = improvement
                            best_move = ('relocate', i, src_gpu, dst_gpu)

        # Try swap moves
        for gpu1 in range(gpu_num):
            for i, model1 in enumerate(placement[gpu1]):
                for gpu2 in range(gpu1 + 1, gpu_num):
                    for j, model2 in enumerate(placement[gpu2]):
                        if (gpu_sizes[gpu1] - model1.model_size + model2.model_size <= GPU_MEM_SIZE and
                            gpu_sizes[gpu2] - model2.model_size + model1.model_size <= GPU_MEM_SIZE):

                            # Simulate swap
                            temp_placement = {}
                            for gid, models_list in placement.items():
                                temp_placement[gid] = list(models_list)

                            temp_placement[gpu1][i], temp_placement[gpu2][j] = model2, model1

                            new_max_kvpr = get_max_kvpr(temp_placement)
                            improvement = current_max_kvpr - new_max_kvpr

                            if improvement > best_improvement:
                                best_improvement = improvement
                                best_move = ('swap', i, gpu1, j, gpu2)

        if best_move is None:
            break

        if best_move[0] == 'relocate':
            _, i, src_gpu, dst_gpu = best_move
            model = placement[src_gpu].pop(i)
            placement[dst_gpu].append(model)
            gpu_sizes[src_gpu] -= model.model_size
            gpu_sizes[dst_gpu] += model.model_size
        else:  # swap
            _, i, gpu1, j, gpu2 = best_move
            model1, model2 = placement[gpu1][i], placement[gpu2][j]
            placement[gpu1][i], placement[gpu2][j] = model2, model1
            gpu_sizes[gpu1] = gpu_sizes[gpu1] - model1.model_size + model2.model_size
            gpu_sizes[gpu2] = gpu_sizes[gpu2] - model2.model_size + model1.model_size

    return placement

