            gpu_current_sizes[best_gpu] += model.model_size

    # Simulated annealing for refinement
    temperature = 1.0
    cooling_rate = 0.95
    iterations = 500

    for _ in range(iterations):
        if temperature < 0.01:
            break

        current_max = max_kvpr(placement)

        # Generate neighbor by moving one model
        src_gpu = random.choice(list(placement.keys()))
        if not placement[src_gpu]:
            continue

        model_idx = random.randrange(len(placement[src_gpu]))
        model_to_move = placement[src_gpu][model_idx]

