        gpu_kvprs = [(gpu_id, calculate_kvpr(models)) for gpu_id, models in placement.items()]
        hot_gpu = max(gpu_kvprs, key=lambda x: x[1])[0]

        if not placement[hot_gpu]:
            continue

        # Try moving each model from hot GPU to another GPU
        for model in list(placement[hot_gpu]):
            for dest_gpu in range(gpu_num):
                if dest_gpu == hot_gpu:
                    continue

                if gpu_current_sizes[dest_gpu] + model.model_size <= GPU_MEM_SIZE:
                    # Create temporary placement
                    temp = {g: list(models) for g, models in placement.items()}
                    temp[hot_gpu].remove(model)
                    temp[dest_gpu].append(model)

                    if max_kvpr(temp) < current_max:
                        placement = temp
                        gpu_current_sizes[hot_gpu] -= model.model_size
                        gpu_current_sizes[dest_gpu] += model.model_size
                        improved = True
                        break
            if improved:
                break

        if not improved:
            break

    return placement
